#include<bits/stdc++.h>
using namespace std;
struct edge
{
    int u,v,w;
}e[10010];
int n,m,r,min1[110],fa[110],top[110],cir[110],tot;
long long ans;
int main()
{
    scanf("%d%d%d",&n,&m,&r);
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d%d",&e[i].u,&e[i].v,&e[i].w);
    }
    while(1)
    {
        for(int i=1;i<=n;i++)
        {
            min1[i]=1e9;
            fa[i]=top[i]=cir[i]=0;
        }
        for(int i=1;i<=m;i++)
        {
            int u=e[i].u,v=e[i].v,w=e[i].w;
            if(u!=v&&w<min1[v])
            {
                min1[v]=w;
                fa[v]=u;
            }
        }
        min1[r]=0;
        for(int i=1;i<=n;i++)
        {
            ans+=min1[i];
            if(min1[i]>=1e9)
            {
                printf("-1");
                return 0;
            }
        }
        for(int i=1,j=1;i<=n;i++,j=i)
        {
            while(j!=r&&top[j]!=i&&!cir[j])
            {
                top[j]=i;
                j=fa[j];
            }
            if(j!=r&&!cir[j])
            {
                cir[j]=++tot;
                for(int k=fa[j];k!=j;k=fa[k])
                {
                    cir[k]=tot;
                }
            }
        }
        if(tot==0)
        {
            printf("%lld",ans);
            return 0;
        }
        for(int i=1;i<=n;i++)
        {
            if(!cir[i])
            {
                cir[i]=++tot;
            }
        }
        for(int i=1;i<=m;i++)
        {
            e[i].w-=min1[e[i].v];
            e[i].u=cir[e[i].u];
            e[i].v=cir[e[i].v];
        }
        n=tot;
        r=cir[r];
        tot=0;
    }
    return 0;
}
